def min_operations_to_portal(t, test_cases):
    results = []

    for case in test_cases:
        n, m, grid = case
        min_operations = float('inf')

        # Iterate over all possible top-left corners of sub-rectangles
        for i in range(n - 4):
            for j in range(m - 3):
                # Iterate over all possible dimensions (a, b)
                for a in range(5, n - i + 1):
                    for b in range(4, m - j + 1):
                        # Calculate the number of operations needed for this sub-rectangle
                        operations = 0

                        # Top and bottom borders (excluding corners)
                        for x in range(1, b - 1):
                            if grid[i][j + x] == '0':
                                operations += 1
                            if grid[i + a - 1][j + x] == '0':
                                operations += 1

                        # Left and right borders (excluding corners)
                        for y in range(1, a - 1):
                            if grid[i + y][j] == '0':
                                operations += 1
                            if grid[i + y][j + b - 1] == '0':
                                operations += 1

                        # Interior
                        for x in range(1, a - 1):
                            for y in range(1, b - 1):
                                if grid[i + x][j + y] == '1':
                                    operations += 1

                        # Update minimum operations
                        min_operations = min(min_operations, operations)

        results.append(min_operations)

    return results

