def is_composite(x):
    if x <= 1:
        return False
    if x <= 3:
        return False
    if x % 2 == 0 or x % 3 == 0:
        return True
    i = 5
    while i * i <= x:
        if x % i == 0 or x % (i + 2) == 0:
            return True
        i += 6
    return False

def find_largest_composite_subset(n, array):
    total_sum = sum(array)
    if is_composite(total_sum):
        return n, list(range(1, n + 1))

    # If the total sum is not composite, we need to remove one element
    # to make the sum composite. Since the array has distinct integers,
    # removing any element will change the sum.
    for i in range(n):
        subset_sum = total_sum - array[i]
        if is_composite(subset_sum):
            indices = [j + 1 for j in range(n) if j != i]
            return n - 1, indices

    # If no single element removal results in a composite sum, 
    # it means the array is such that removing any element results in a prime sum.
    # In this case, we can safely return the whole array as the subset.
    return n, list(range(1, n + 1))

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    index = 0
    t = int(data[index])
    index += 1
    results = []

    for _ in range(t):
        n = int(data[index])
        index += 1
        array = list(map(int, data[index:index + n]))
        index += n

        size, indices = find_largest_composite_subset(n, array)
        results.append(f"{size}\n{' '.join(map(str, indices))}")

    print("\n".join(results))

